INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-3218f787-moex-00106', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「每日晨禱，我與同仁們一起唸〈天主經〉，晚上睡前我則獨自唸《大悲咒》，迴 向給一切眾生作為一天的結束。忽然，我驚覺我正在體驗馬天賜神父過去的交談經 驗，他曾在菲律賓的醫院陪伴垂死之人，如今我在臺東唯一的安寧病房體驗生命。 馬神父在自己的宗教團體裡開啟宗教交談，我則是以佛教徒的身分在天主教機構裡 實踐宗教交談。我喜歡欣賞不同宗教之間的互動，但也維持著一定的距離。在不同 宗教團體裡的學習是連續性的，他們的一言一行不斷激盪著我的慣性思維。」 根據上文，下列選項何者正確？', '["在臺東安寧病房的體驗，顯示不同宗教雖有差異，但藉由彼此的互動學習，可互 相激盪啟發", "以佛教徒的身分穿梭在天主教機構裡，體會不同教義的不同美好，也使自己原本 的信仰更加堅定", "〈天主經〉與《大悲咒》都是外在的客觀知識，因此作者白天晚上分別閱讀念誦， 完全不會有矛盾", "因為「我」是佛教徒，跟不同宗教都必須維持一定的距離，只能勉力學習和別的 教徒交談並研讀其經典"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00107', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「理性選擇不是分析人類選擇機制的心理學，也不規範人類應該如何進行選擇。它 著重於選擇是否符合行為人的價值觀，而理性的重點則在於選擇是否符合行為人的 目標，因此兩者息息相關。」 根據上文，下列選項何者最能彰顯理性選擇的表現？', '["萬物靜觀皆自得", "不為五斗米折腰", "天生我材必有用", "事如春夢了無痕"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00108', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「創新，就是開創的能力，可分為兩個層次來談。第一是『無中生有』：去發現尚 未嘗試過的使用者介面或是消費者族群；第二是『異中求同』，就是把既有的線索， 連結在一起變成新的東西。創新常是先有一些『趨之若鶩』的想法，然後再思考要 如何執行。此外，創新也要能『三思而行』不怕犯錯，從錯誤中學習全新的事物。」 上述文句『』中的詞語，運用正確的是：', '["無中生有", "異中求同", "趨之若鶩", "三思而行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00109', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「其實人與人之間，或為親情或為友情或為愛情，那一種親密的情誼不是基於我在 這裡，剛好，你也在這裡的前題？一切的愛，不就是『同在』的緣份嗎？就連神明， 其所以為神明，也無非由於『昔在、今在、恆在』，以及『無所不在』的特質。而 身為一個人，我對自己『只能出現於這個時間和空間的局限』感到另一種可貴，彷 彿我是拼圖板上扭曲奇特的一塊小形狀，單獨看，毫無意義，及至嵌在適當的時空， 恰恰也是不可少的一塊。」 下列選項，何者與上文旨趣最相近？', '["自覺存有，無所不在", "閒雅自適，進退中度", "敢作敢為，自得其樂", "貴於同在，堅定自信"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00110', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「媽媽離世以後，我讓自己瘋狂投入各種祭祀，專心致志到一定程度，可能有什麼 心理學的脈絡可追溯，但根據趨吉避凶的直覺，我傾向不去細究。傳統殯俗的食材 宜忌，常帶有閩南語雙關語，合宜的，意在祝福後代，如豆干做大官、肉丸中狀元 一類，包含一切古代社會對功成名就的僵固想像。但由於祭祀對象是我那相當愛聽 吉祥話的媽媽，我決定全盤買單照辦，不與之論辯。比如水果成串的不能拜，因憾 事不能成串而來。比如豆子可以是荷蘭豆、四季豆、甘納豆，但長豆竟不能，因長 豆象徵長壽。」 下列選項，何者最貼合文意？', '["祭祀時，作者會依照媽媽的喜愛，準備其喜歡的荔枝龍眼葡萄", "祭祀食材常希望福蔭子孫，選擇豆干、肉丸等祭品，避用長豆", "作者因母親離世的心理創傷，成了瘋狂投入各種祭祀的迷信者", "作者認為祭祀選用的食材，都是古代社會對於忌諱的僵固想像"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00111', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「在我們平凡的人生中，對於宏偉的體會通常是一種稍縱即逝的狀態，多多少少是 隨機出現的情形。……不過，藝術能夠消除隨機與偶然性，因為藝術提供的工具能 夠穩定促成對我們有益的體驗，所以每當我們從自己的悲傷當中抬起頭來，即可接 觸到這樣的體驗。」 下列對自然景物描寫的文句中，何者最貼合上述引文的文意？', '["然後，就在那光與色的動晃中，忽然那太陽，像巨大的蛋黃，像橘紅淋漓的一團 烙鐵漿，蹦跳而出，雲彩炫耀。世界彷彿一時間豁然開朗，山脈谷地於是有了較 分明的光影", "形成八通關草原的玉山箭竹，即是火焚後由於地下莖的堅韌與活躍而率先抽芽再 生的先鋒植物。草原上並且也已出現了諸如杜鵑和馬醉木之類的灌木，以及疏落 散生的二葉松小喬木。植物演替逐漸由簡趨繁", "森林到此已是生長的極限了；界線以下是筆直昂立、林相優美的冷杉林，以上則 是樹型迥然不同的玉山圓柏和玉山杜鵑所代表的矮盤灌叢帶，以及更往上以至峰 頂的岩地草本植物帶，涇渭分明", "在濃綠的針葉枝椏間，牠們小巧的身軀和煤灰色的外表，並不突出，但透過望遠 鏡仔細打量，卻不得不讚嘆那素樸的容顏自有其高雅迷人的風味，而那短短的黑 色冠羽，則堅持了某種驕矜的神氣和俏皮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00112', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「某架飛機因飛行員操作失誤，機尾擦到地面，使得飛機蒙皮受損。正確的維修方 式，必須把整塊蒙皮換掉。但維修人員卻只是在受損處補上一小片外皮，再以噴漆 修飾，接著做假的維修紀錄，蒙混過關。若干年後，該架飛機因機尾斷裂，失事墜 海。追究失事的原因，正是之前機尾未確實修補所致。」 根據上文，下列選項最符合的是：', '["棄實務華，只求形似", "千里之行，始於足下", "千里之堤，潰於蟻穴", "明修棧道，暗渡陳倉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00113', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「討海人擁有兩個家和兩種家人。一個家在穩固的陸地上，另個家，漂在海上。親 情關係維持著的是岸上那個家的家人，討海夥伴關係維繫的是海上另一個家的另一 種家人。想想也是，以岸上那個家來說，討海工作是踏出家門打拚，海上這個家， 則是『家』和『家人』一起離岸離港，一起戰浪搏魚。」 根據上文，對於「討海人」的敘述，正確的是：', '["居無定所，四處漂泊為家", "時間平均分配給兩種家人", "陸地上的家才是真正的家", "海上家人是一種夥伴關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00114', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-0b2477b6', 'sub-generalpolice-3218f787-03', NULL, 'essay', '在人際互動中，他人常運用不同的策略使得我們最終同意他們所提出的
